data: {"type":"response.code_interpreter_call_code.done","code":"import matplotlib.pyplot as plt\nimport numpy as np\n\n# Generate Mandelbrot set image\ndef mandelbrot(c, max_iter):\n    z = c\n    for n in range(max_iter):\n        if abs(z) > 2:\n            return n\n        z = z*z + c\n    return max_iter\n\n# Define image size and limits\nwidth, height = 800, 600\nx_min, x_max = -2.0, 1.0\ny_min, y_max = -1.0, 1.0\nmax_iter = 100\n\n# Create image\nimage = np.zeros((height, width))\nfor row in range(height):\n    for col in range(width):\n        x = x_min + (x_max - x_min) * col / (width - 1)\n        y = y_min + (y_max - y_min) * row / (height - 1)\n        c = complex(x, y)\n        color = mandelbrot(c, max_iter)\n        image[row, col] = color\n\n# Plotting the Mandelbrot set\nplt.figure(figsize=(10, 7.5))\nplt.imshow(image, extent=(x_min, x_max, y_min, y_max), cmap='hot')\nplt.colorbar()\nplt.title('Mandelbrot Set')\nplt.xlabel('Re')\nplt.ylabel('Im')\nplt.tight_layout()\n\n# Save to PDF\nfile_path = \"/mnt/data/mandelbrot_set.pdf\"\nplt.savefig(file_path, format='pdf')\nplt.close()\n\nfile_path","item_id":"ci_069e54241b4e58180069b30e4c49d08190aade53234f5ad60d","output_index":0,"sequence_number":322}

